function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
  return cells.filter((other) => isNeighbor(cell, other)).length;
}

function isNeighbor([x, y]: Cell, [ox, oy]: Cell): boolean {
  const dx = Math.abs(ox - x);
  const dy = Math.abs(oy - y);
  const isWithinRange = dx <= 1 && dy <= 1;
  const isSameCell = dx === 0 && dy === 0;
  return isWithinRange && !isSameCell;
}
